def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score = ratio ** 4 + np.sqrt(ratio)
        elif 1 < ratio <= 2:
            score = (ratio - 1) ** 2 * 10
        elif ratio == 1:
            score = 0
        else:
            log_ratio = np.log(ratio)
            if log_ratio < -2:
                score = -10 * log_ratio + 5
            elif -2 <= log_ratio < -0.5:
                score = -3 * log_ratio + ratio
            else:
                score = -log_ratio + 0.3 * ratio
        if capacity < item * 0.3:
            score += 4
        elif item * 0.3 <= capacity < item * 0.7:
            score += 1
        elif capacity > item * 3:
            score -= 2
        if i % 2 == 0:
            score *= 0.9
        else:
            score *= 1.1
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority + 15
            else:
                if priorities[i] > (min_priority + max_priority) / 2:
                    priorities[i] *= 1.05
                else:
                    priorities[i] *= 0.95
    return priorities
